// Chat-GPT 生成
#include <bits/stdc++.h>
using namespace std;

const int N = 5e5 + 10;

int n, m, w, a[N], pre[N], t[N * 4], lst[N];
set<int> st[N];

void build(int cur, int l, int r) {
    if (l == r) {
        t[cur] = pre[l];
        return;
    }
    int mid = (l + r) >> 1;
    build(cur * 2, l, mid);
    build(cur * 2 + 1, mid + 1, r);
    t[cur] = max(t[cur * 2], t[cur * 2 + 1]);
}

void modify(int cur, int l, int r, int x, int k) {
    if (l == r) {
        t[cur] = pre[l] = k;
        return;
    }
    int mid = (l + r) >> 1;
    if (x <= mid)
        modify(cur * 2, l, mid, x, k);
    else
        modify(cur * 2 + 1, mid + 1, r, x, k);
    t[cur] = max(t[cur * 2], t[cur * 2 + 1]);
}

int query(int cur, int l, int r, int x, int y) {
    if (x <= l && r <= y)
        return t[cur];
    int mid = (l + r) >> 1, res = 0;
    if (x <= mid)
        res = max(res, query(cur * 2, l, mid, x, y));
    if (y > mid)
        res = max(res, query(cur * 2 + 1, mid + 1, r, x, y));
    return res;
}

int main() {
    scanf("%d%d%d", &n, &m, &w);
    for (int i = 1; i <= n; i++)
        scanf("%d", &a[i]);

    // 初始化 lst 和 st
    for (int i = 1; i <= n; i++) {
        if (lst[w - a[i]]) pre[i] = lst[w - a[i]], lst[w - a[i]] = 0;
        lst[a[i]] = i;
        st[a[i]].insert(i);
    }
    for (int i = 0; i <= w; i++) {
        st[i].insert(0);
        st[i].insert(n + 1);
    }
    build(1, 1, n);

    int cnt = 0;
    while (m--) {
        int op, x, y;
        scanf("%d%d%d", &op, &x, &y);
        if (op == 1) {
            int p = *st[w - a[x]].upper_bound(x), lx, lp, rx;
            if (pre[p] == x) {
                lx = *prev(st[a[x]].lower_bound(x)), lp = *prev(st[w - a[x]].upper_bound(x));
                if (pre[lp] != lx || lp == x)
                    modify(1, 1, n, p, lx);
                else
                    modify(1, 1, n, p, 0);
            }
            rx = *st[a[x]].upper_bound(x);
            if (rx <= n && !pre[rx])
                modify(1, 1, n, rx, pre[x]);
            st[a[x]].erase(x);
            st[a[x] = y].insert(x);
            rx = *st[a[x]].upper_bound(x);
            if (rx <= n && pre[rx] < x)
                modify(1, 1, n, rx, 0);
            p = *st[w - a[x]].upper_bound(x);
            if (p <= n && pre[p] < x)
                modify(1, 1, n, p, x);
            p = *prev(st[w - a[x]].lower_bound(x));
            lx = *st[a[x]].upper_bound(p);
            if (lx == x)
                modify(1, 1, n, x, p);
            else
                modify(1, 1, n, x, 0);
        } else {
            x ^= cnt;
            y ^= cnt;
            if (query(1, 1, n, x, y) >= x) {
                cnt++;
                puts("Yes");
            } else
                puts("No");
        }
    }
    return 0;
}
